import { useState } from "react";
import Btn from "./components/ui/Btn";
import Badge from "../components/ui/Badge";

const StudentsPage = ({ students, onAssign, onRemove }) => {
  const [search, setSearch] = useState("");
  const filtered = students.filter(s =>
    s.name?.toLowerCase().includes(search.toLowerCase()) ||
    s.email?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <h2 style={{ fontSize: 22, fontWeight: 800, color: "#1e293b", marginBottom: 24 }}>👥 Students</h2>
      <input
        placeholder="🔍 Search students..."
        value={search} onChange={e => setSearch(e.target.value)}
        style={{ width: "100%", boxSizing: "border-box", padding: "10px 16px", borderRadius: 10, border: "1.5px solid #e2e8f0", fontSize: 14, marginBottom: 20, outline: "none", fontFamily: "inherit" }}
      />
      <div style={{ background: "#fff", borderRadius: 16, boxShadow: "0 2px 16px rgba(30,41,59,0.07)", overflow: "auto" }}>
        <table style={{ width: "100%", borderCollapse: "collapse" }}>
          <thead>
            <tr style={{ background: "#f8fafc", borderBottom: "1px solid #e2e8f0" }}>
              {["Name", "Email", "Course", "Year", "Room", "Actions"].map(h => (
                <th key={h} style={{ padding: "12px 16px", textAlign: "left", fontSize: 13, fontWeight: 700, color: "#475569" }}>{h}</th>
              ))}
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 ? (
              <tr><td colSpan={6} style={{ padding: 32, textAlign: "center", color: "#94a3b8" }}>No students found</td></tr>
            ) : filtered.map(s => (
              <tr key={s.id} style={{ borderBottom: "1px solid #f1f5f9" }}>
                <td style={{ padding: "12px 16px", fontWeight: 600 }}>{s.name}</td>
                <td style={{ padding: "12px 16px", color: "#64748b" }}>{s.email}</td>
                <td style={{ padding: "12px 16px" }}>{s.course}</td>
                <td style={{ padding: "12px 16px" }}>{s.year}</td>
                <td style={{ padding: "12px 16px" }}>
                  {s.roomId ? <Badge color="green">{s.roomId}</Badge> : <Badge color="gray">Unassigned</Badge>}
                </td>
                <td style={{ padding: "12px 16px" }}>
                  {!s.roomId ? (
                    <Btn onClick={() => onAssign(s)} style={{ padding: "6px 14px", fontSize: 12 }}>Assign Room</Btn>
                  ) : (
                    <Btn variant="danger" onClick={() => onRemove(s.id)} style={{ padding: "6px 14px", fontSize: 12 }}>Remove</Btn>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StudentsPage;
